UPDATE  EDT_MSG_INFO
SET     VIEW_CNT = ( SELECT * FROM ( SELECT MAX(IFNULL(VIEW_CNT,0)) + 1 FROM EDT_MSG_INFO WHERE SEQ = #{SEQ} ) AS A)
WHERE   SEQ = #{SEQ}

/* jaram.menu.mapper.CommunityMapper.updateNowSession */
UPDATE  EDT_MSG_INFO
SET     NOW_SESSION = #{NOW_SESSION}
WHERE   SEQ = #{SEQ}

mapper.insert:
/* jaram.common.mapper.CommonMapper.insertComment */
 INSERT INTO BOARD_COMMENT
 (
       COMMENT_SEQ
     , EDT_SEQ
     , COMMENT_DEPTH
     , COMMENT_TEXT
     , COMMENT_PASSWORD
     , PARENT_COMMENT_SEQ
     , SECURE_YN
     , IMG_PATH
     , INPUT_DT
     , INPUT_ID
     , INPUT_NAME
     , UPDATE_DT
     , UPDATE_ID
     , UPDATE_NAME
 )
 VALUE
 (
       #{COMMENT_SEQ}
     , #{EDT_SEQ}
     , #{COMMENT_DEPTH}
     , #{COMMENT_TEXT}
     , #{COMMENT_PASSWORD}
     , IFNULL(#{SECURE_YN}, 'N')
     , #{PARENT_COMMENT_SEQ}
     , #{IMG_PATH}
     , IFNULL(#{INPUT_DT}, NOW(3))
     , #{INPUT_ID}
     , #{INPUT_NAME}
     , NOW()
     , #{UPDATE_ID}
     , #{UPDATE_NAME}
     )
 ON DUPLICATE KEY UPDATE
      COMMENT_TEXT     = #{COMMENT_TEXT}
    , SECURE_YN   = IFNULL(#{SECURE_YN}, 'N')
    , UPDATE_DT   = NOW()
    , UPDATE_ID   = #{INPUT_ID}

