/* jaram.common.mapper.CommonMapper.deleteComment [댓글 삭제]*/
UPDATE  BOARD_COMMENT
SET     DEL_YN = 'Y'
WHERE   COMMENT_SEQ = #{COMMENT_SEQ}

/* jaram.common.mapper.CommonMapper.updateComment [댓글 수정]*/
UPDATE  BOARD_COMMENT
SET     COMMENT_TEXT = #{COMMENT_TEXT}
      , IMG_PATH     = #{IMG_PATH}
WHERE   COMMENT_SEQ  = #{COMMENT_SEQ}
